mapper.select:
SELECT * FROM (
    SELECT T.*, ROWNUM AS RNUM FROM (
        SELECT TITLE, AUTHOR, PUBLISHER, CATEGORY_CODE, CURRENT_CNT
        FROM BOOK

        ORDER BY TITLE ASC
    ) T

    WHERE ROWNUM <= #{firstIndex} + #{recordCount}

)
WHERE RNUM > #{firstIndex}

mapper.update:
UPDATE BOOK
TITLE = #{title}, AUTHOR = #{author}, PUBLISHER = #{publisher}, CATEGORY_CODE = #{categoryCode}, BOOK_DESC = #{bookDesc},
WHERE BOOK_ID = #{bookId}

UPDATE BOOK
TOTAL_CNT = #{totalCnt}, CURRENT_CNT = #{currentCnt}, DAMAGED_CNT = #{damagedCnt},
WHERE BOOK_ID = #{bookId}
